const po = ($input.first().json?.data || $input.first().json) || {};
const trackingId = `PO-${Date.now().toString(36).toUpperCase()}`;
const grandTotal = parseFloat(po.grandTotal) || 0;
const subtotal   = parseFloat(po.subtotal)   || 0;
const grandTotalFormatted = grandTotal.toLocaleString('en-US', {minimumFractionDigits:2, maximumFractionDigits:2});

let approvalLevel = 'Auto-Approve';
if (grandTotal >= 25000)     approvalLevel = 'VP/CFO Approval';
else if (grandTotal >= 5000) approvalLevel = 'Director Approval';
else if (grandTotal >= 1000) approvalLevel = 'Manager Approval';

let urgency = 'Normal'; let daysUntilRequired = null;
if (po.requiredDate) {
  const req = new Date(po.requiredDate); const today = new Date();
  daysUntilRequired = Math.ceil((req - today) / (1000*60*60*24));
  if (daysUntilRequired <= 3) urgency = 'Urgent';
  else if (daysUntilRequired <= 7) urgency = 'High';
}

return [{ json: {
  trackingId,
  poNumber:     po.poNumber     || 'N/A',
  vendorName:   po.vendorName   || 'N/A',
  orderDate:    po.orderDate    || 'N/A',
  requiredDate: po.requiredDate || 'N/A',
  lineItemCount: parseInt(po.lineItemCount) || 0,
  lineItemsList: po.lineItemsList || 'N/A',
  subtotal, grandTotal, grandTotalFormatted,
  shippingCost: parseFloat(po.shippingCost) || 0,
  tax:          parseFloat(po.tax)          || 0,
  approvalLevel, urgency, daysUntilRequired,
  paymentTerms: po.paymentTerms || 'N/A',
  processedAt: new Date().toISOString()
}}];

